// Improved application with security best practices
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const validator = require('validator');

const app = express();

// ✅ Security middleware
app.use(helmet()); // Sets secure HTTP headers
app.use(express.json({ limit: '10kb' })); // Body size limit
app.use(express.urlencoded({ limit: '10kb', extended: true }));

// ✅ Rate limiting
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100, // Limit each IP to 100 requests per windowMs
  message: 'Too many requests from this IP, please try again later.',
});
app.use(limiter);

// ✅ Request logging middleware (security audit trail)
app.use((req, res, next) => {
  console.log(`[${new Date().toISOString()}] ${req.method} ${req.path}`);
  next();
});

// ✅ Health check with error handling
app.get('/health', (req, res) => {
  try {
    res.json({ 
      status: 'ok', 
      timestamp: new Date().toISOString(),
      uptime: process.uptime()
    });
  } catch (error) {
    console.error('Health check error:', error);
    res.status(500).json({ status: 'error', message: 'Internal server error' });
  }
});

// ✅ Users endpoint with input validation
app.get('/users', (req, res) => {
  try {
    // Validate query parameters
    const { id, email } = req.query;

    if (id && !validator.isInt(id)) {
      return res.status(400).json({ 
        error: 'Invalid ID parameter', 
        message: 'ID must be an integer' 
      });
    }

    if (email && !validator.isEmail(email)) {
      return res.status(400).json({ 
        error: 'Invalid email parameter', 
        message: 'Email must be a valid format' 
      });
    }

    const users = [
      { id: 1, name: 'Alice', email: 'alice@example.com' },
      { id: 2, name: 'Bob', email: 'bob@example.com' },
    ];

    // Filter based on validated parameters
    let filtered = users;
    if (id) {
      filtered = filtered.filter(u => u.id === parseInt(id, 10));
    }
    if (email) {
      filtered = filtered.filter(u => u.email === email.toLowerCase());
    }

    res.json(filtered);
  } catch (error) {
    console.error('Users endpoint error:', error);
    res.status(500).json({ 
      error: 'Internal server error',
      message: 'An unexpected error occurred' 
    });
  }
});

// ✅ 404 handler
app.use((req, res) => {
  res.status(404).json({ 
    error: 'Not Found', 
    message: 'The requested endpoint does not exist' 
  });
});

// ✅ Global error handling middleware
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);

  // Avoid leaking sensitive information
  const status = err.status || 500;
  const message = process.env.NODE_ENV === 'production' 
    ? 'Internal server error' 
    : err.message;

  res.status(status).json({ 
    error: 'Server Error',
    message,
    ...(process.env.NODE_ENV !== 'production' && { stack: err.stack })
  });
});

// ✅ Handle unhandled promise rejections
process.on('unhandledRejection', (reason, promise) => {
  console.error('Unhandled Rejection at:', promise, 'reason:', reason);
});

// ✅ Handle uncaught exceptions
process.on('uncaughtException', (error) => {
  console.error('Uncaught Exception:', error);
  process.exit(1);
});

const PORT = process.env.PORT || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

// ✅ Graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM received, shutting down gracefully...');
  server.close(() => {
    console.log('Server closed');
    process.exit(0);
  });
});

module.exports = app;
```

